1013→        || id.starts_with("tts-")
1014→        || id.starts_with("whisper")
1015→        || id.starts_with("text-embedding")
1016→        || id.starts_with("claude-embedding")
1017→        || id.starts_with("claude-embeddings")
1018→        || id.starts_with("omni-moderation")
