1062→/// Check if a model supports reasoning/extended thinking.
1063→///
1064→/// Reasoning-capable models can use the `reasoning_effort` configuration
1065→/// to control the depth of extended thinking. This is used by the UI and
1066→/// validation to inform users when reasoning_effort is set on a model
1067→/// that doesn't support it.
1068→pub fn supports_reasoning_for_model(model_id: &str) -> bool {
1069→    let id = capability_model_id(model_id);
1070→    // Anthropic Claude Opus 4.5+ and Sonnet 4.5+
1071→    if id.starts_with("claude-opus-4-5")
1072→        || id.starts_with("claude-sonnet-4-5")
1073→        || id.starts_with("claude-opus-4-6")
1074→        || id.starts_with("claude-sonnet-4-6")
1075→    {
1076→        return true;
1077→    }
1078→    // Claude 3.7 Sonnet supports extended thinking
1079→    if id.starts_with("claude-3-7-sonnet") {
1080→        return true;
1081→    }
1082→    // OpenAI o-series reasoning models
1083→    if id.starts_with("o1") || id.starts_with("o3") || id.starts_with("o4") {
1084→        return true;
1085→    }
1086→    // Gemini 2.5 Flash/Pro with thinking
1087→    if id.starts_with("gemini-2.5") {
1088→        return true;
1089→    }
1090→    // OpenAI GPT-5.x models support reasoning_effort
1091→    if id.starts_with("gpt-5") {
1092→        return true;
1093→    }
1094→    // DeepSeek R1 / reasoning models
1095→    if id.contains("deepseek-r1") || id.contains("deepseek-reasoner") {
1096→        return true;
1097→    }
1098→    false
1099→}

