382→/// Spawn model discovery in a background thread and return the receiver
383→/// immediately, without blocking. Call `.recv()` later to collect the result.
384→pub fn start_model_discovery(
385→    api_key: secrecy::Secret<String>,
386→    base_url: String,
387→) -> mpsc::Receiver<anyhow::Result<Vec<super::DiscoveredModel>>> {
388→    let (tx, rx) = mpsc::sync_channel(1);
389→    std::thread::spawn(move || {
390→        let result = tokio::runtime::Builder::new_current_thread()
391→            .enable_all()
392→            .build()
393→            .map_err(anyhow::Error::from)
394→            .and_then(|rt| rt.block_on(fetch_models_from_api(api_key, base_url)));
395→        let _ = tx.send(result);
396→    });
397→    rx
398→}
