221→fn parse_models_payload(value: &serde_json::Value) -> Vec<super::DiscoveredModel> {
222→    let mut candidates = Vec::new();
223→    collect_candidate_arrays(value, &mut candidates);
224→
225→    let mut models = Vec::new();
226→    let mut seen = HashSet::new();
227→    for entry in candidates {
228→        if let Some(model) = parse_model_entry(entry)
229→            && is_chat_capable_model(&model.id)
230→            && seen.insert(model.id.clone())
231→        {
232→            models.push(model);
233→        }
234→    }
235→
236→    // Sort by created_at descending (newest first). Models without a
237→    // timestamp are placed after those with one, preserving relative order.
238→    models.sort_by(|a, b| match (a.created_at, b.created_at) {
239→        (Some(a_ts), Some(b_ts)) => b_ts.cmp(&a_ts), // newest first
240→        (Some(_), None) => std::cmp::Ordering::Less, // timestamp before no-timestamp
241→        (None, Some(_)) => std::cmp::Ordering::Greater,
242→        (None, None) => std::cmp::Ordering::Equal,
243→    });
244→
245→    models
246→}
