265→const OPENAI_MAX_TOOL_CALL_ID_LEN: usize = 40;
266→
267→fn short_stable_hash(value: &str) -> String {
268→    use std::hash::{Hash, Hasher};
269→
270→    let mut hasher = std::collections::hash_map::DefaultHasher::new();
271→    value.hash(&mut hasher);
272→    format!("{:016x}", hasher.finish())
273→}
274→
275→fn base_openai_tool_call_id(raw: &str) -> String {
276→    let mut cleaned: String = raw
277→        .chars()
278→        .map(|ch| {
279→            if ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-') {
280→                ch
281→            } else {
282→                '_'
283→            }
284→        })
285→        .collect();
286→
287→    if cleaned.is_empty() {
288→        cleaned = "call".to_string();
289→    }
290→
291→    if cleaned.len() <= OPENAI_MAX_TOOL_CALL_ID_LEN {
292→        return cleaned;
293→    }
294→
295→    let hash = short_stable_hash(raw);
296→    let keep = OPENAI_MAX_TOOL_CALL_ID_LEN.saturating_sub(hash.len() + 1);
297→    cleaned.truncate(keep);
298→    if cleaned.is_empty() {
299→        return format!("call-{hash}");
300→    }
301→    format!("{cleaned}-{hash}")
302→}
303→
304→fn disambiguate_tool_call_id(base: &str, nonce: usize) -> String {
305→    let suffix = format!("-{nonce}");
306→    let keep = OPENAI_MAX_TOOL_CALL_ID_LEN.saturating_sub(suffix.len());
307→
308→    let mut value = base.to_string();
309→    if value.len() > keep {
310→        value.truncate(keep);
311→    }
312→    if value.is_empty() {
313→        value = "call".to_string();
314→        if value.len() > keep {
315→            value.truncate(keep);
316→        }
317→    }
318→    format!("{value}{suffix}")
319→}
