321→fn assign_openai_tool_call_id(
322→    raw: &str,
323→    remapped_tool_call_ids: &mut HashMap<String, String>,
324→    used_tool_call_ids: &mut HashSet<String>,
325→) -> String {
326→    if let Some(existing) = remapped_tool_call_ids.get(raw) {
327→        return existing.clone();
328→    }
329→
330→    let base = base_openai_tool_call_id(raw);
331→    let mut candidate = base.clone();
332→    let mut nonce = 1usize;
333→    while used_tool_call_ids.contains(&candidate) {
334→        candidate = disambiguate_tool_call_id(&base, nonce);
335→        nonce = nonce.saturating_add(1);
336→    }
337→
338→    used_tool_call_ids.insert(candidate.clone());
339→    remapped_tool_call_ids.insert(raw.to_string(), candidate.clone());
340→    candidate
341→}
