 67→/// A model discovered from a provider API (e.g. `/v1/models`).
 68→///
 69→/// Replaces bare `(String, String)` tuples so that optional metadata
 70→/// such as `created_at` can travel alongside the id/display_name pair.
 71→#[derive(Debug, Clone)]
 72→pub struct DiscoveredModel {
 73→    pub id: String,
 74→    pub display_name: String,
 75→    /// Unix timestamp from the API (e.g. OpenAI `created` field).
 76→    /// Used to sort models newest-first. `None` for static catalog entries.
 77→    pub created_at: Option<i64>,
 78→    /// Flagged by the provider as a recommended/flagship model.
 79→    /// Used to surface the most relevant models in the UI.
 80→    pub recommended: bool,
 81→}
 82→
 83→impl DiscoveredModel {
 84→    pub fn new(id: impl Into<String>, display_name: impl Into<String>) -> Self {
 85→        Self {
 86→            id: id.into(),
 87→            display_name: display_name.into(),
 88→            created_at: None,
 89→            recommended: false,
 90→        }
 91→    }
 92→
 93→    pub fn with_created_at(mut self, created_at: Option<i64>) -> Self {
 94→        self.created_at = created_at;
 95→        self
 96→    }
 97→
 98→    pub fn with_recommended(mut self, recommended: bool) -> Self {
 99→        self.recommended = recommended;
100→        self
101→    }
102→}
