104→/// Convert a static model catalog into `DiscoveredModel` entries, marking
105→/// the first `recommended_count` as recommended.
106→pub fn catalog_to_discovered(
107→    catalog: &[(&str, &str)],
108→    recommended_count: usize,
109→) -> Vec<DiscoveredModel> {
110→    catalog
111→        .iter()
112→        .enumerate()
113→        .map(|(i, (id, name))| {
114→            DiscoveredModel::new(*id, *name).with_recommended(i < recommended_count)
115→        })
116→        .collect()
117→}
